-- ENGINEER_WRITTEN 2025년 제3회 기출 복원 — 100문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 재실행 안전성 — 동일 조합(exam_type + PAST_EXAM + 연도/회차) 정리 후 재삽입
DELETE FROM mock_exam
  WHERE exam_type = 'ENGINEER_WRITTEN'
    AND kind = 'PAST_EXAM'
    AND exam_year = 2025
    AND exam_round = 3;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'ENGINEER_WRITTEN');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('정보처리기사 필기 2025년 3회 복원', 'ENGINEER_WRITTEN', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2025, 3, '2025-07-05', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '애자일(Agile) 개발 방법론의 유형으로 보기 어려운 것은?\n\n① XP(Extreme Programming)\n② Scrum\n③ SPICE\n④ Crystal', 'MCQ', 3, '정답: 3. SPICE는 소프트웨어 프로세스를 평가하기 위한 국제 표준이며, 애자일 개발 방법론의 한 유형이 아니다.\n\n**오답 풀이**\n- 1번: XP는 대표적인 애자일 방법론이다.\n- 2번: Scrum은 대표적인 애자일 방법론이다.\n- 3번: SPICE는 프로세스 평가 모델에 해당한다.\n- 4번: Crystal은 애자일 방법론의 한 갈래이다.\n\n**보충 개념**\n애자일 방법론에는 XP, Scrum, Crystal, FDD, ASD 등이 있다.',
   '애자일', 1, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '디자인 패턴의 분류 중 행위(Behavioral) 패턴에 속하는 것은?\n\n① Bridge\n② Decorator\n③ Observer\n④ Proxy', 'MCQ', 3, '정답: 3. Observer는 객체의 상태가 변할 때 의존하는 객체들에게 알림을 전달하는 행위 패턴이다.\n\n**오답 풀이**\n- 1번: Bridge는 구조 패턴이다.\n- 2번: Decorator는 구조 패턴이다.\n- 3번: Observer는 행위 패턴이다.\n- 4번: Proxy는 구조 패턴이다.\n\n**보충 개념**\nGoF 디자인 패턴은 생성, 구조, 행위 패턴으로 구분된다.',
   '디자인 패턴', 1, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'UI 설계 원칙 중 사용자가 의도한 목표를 정확하고 완전하게 달성할 수 있도록 유도하는 원칙은?\n\n① 직관성\n② 유효성\n③ 학습성\n④ 유연성', 'MCQ', 2, '정답: 2. 유효성은 사용자의 목적을 정확하고 완전하게 달성할 수 있도록 설계하는 원칙이다.\n\n**오답 풀이**\n- 1번: 직관성은 별도의 학습 없이도 쉽게 이해하고 사용할 수 있는 정도이다.\n- 2번: 유효성은 사용자의 목표 달성 여부와 관련된다.\n- 3번: 학습성은 사용자가 쉽게 배우고 익힐 수 있는 정도이다.\n- 4번: 유연성은 사용자의 요구를 수용하고 오류를 최소화하는 정도이다.\n\n**보충 개념**\nUI 설계 원칙에는 직관성, 유효성, 학습성, 유연성이 있다.',
   'UI 설계', 1, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'CASE(Computer Aided Software Engineering) 도구의 주요 기능으로 옳지 않은 것은?\n\n① 소프트웨어 생명주기 전 단계의 자동화\n② 모델링 간의 모순 검사\n③ 프로그램 언어와 번역 및 실행\n④ 오류 검증 및 자료 흐름도 작성', 'MCQ', 3, '정답: 3. CASE 도구는 개발 생명주기 자동화와 모델링·분석을 지원하지만, 프로그램 언어 번역과 실행 자체를 주된 기능으로 두지는 않는다.\n\n**오답 풀이**\n- 1번: CASE는 개발 전 과정의 자동화를 지원한다.\n- 2번: 모델 간의 모순 검사와 일관성 점검을 지원할 수 있다.\n- 3번: 언어 번역과 실행은 컴파일러나 실행 환경의 역할에 가깝다.\n- 4번: 오류 검증과 자료 흐름도 작성은 CASE 도구가 지원하는 활동이다.\n\n**보충 개념**\nCASE는 요구분석, 설계, 구현, 테스트 등 SW 개발 활동 전반을 지원하는 자동화 도구이다.',
   'CASE', 2, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 아키텍처 패턴 중 입력 데이터를 받아 처리한 결과를 다음 서브시스템으로 넘기는 과정을 반복하는 구조는?\n\n① Master-Slave\n② Pipe-Filter\n③ Layered Pattern\n④ Peer-to-Peer', 'MCQ', 2, '정답: 2. Pipe-Filter 패턴은 각 필터가 데이터를 가공한 뒤 파이프를 통해 다음 필터로 전달하는 구조이다.\n\n**오답 풀이**\n- 1번: Master-Slave는 주 컴포넌트가 하위 컴포넌트를 제어하는 구조이다.\n- 2번: Pipe-Filter는 순차적 데이터 처리에 적합하다.\n- 3번: Layered Pattern은 계층별로 책임을 분리하는 구조이다.\n- 4번: Peer-to-Peer는 각 노드가 대등하게 통신하는 구조이다.\n\n**보충 개념**\nPipe-Filter 패턴은 컴파일러, 데이터 변환 파이프라인, 스트림 처리에 자주 활용된다.',
   '파이프-필터', 2, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'UML 다이어그램 중 정적(Static) 다이어그램에 속하지 않는 것은?\n\n① 클래스 다이어그램(Class Diagram)\n② 객체 다이어그램(Object Diagram)\n③ 순차 다이어그램(Sequence Diagram)\n④ 컴포넌트 다이어그램(Component Diagram)', 'MCQ', 3, '정답: 3. 순차 다이어그램은 객체 사이의 메시지 흐름을 시간 순서로 표현하는 동적 행위 다이어그램이다.\n\n**오답 풀이**\n- 1번: 클래스 다이어그램은 정적 구조 다이어그램이다.\n- 2번: 객체 다이어그램은 특정 시점의 객체 구조를 표현한다.\n- 3번: 순차 다이어그램은 동적 행위 다이어그램이다.\n- 4번: 컴포넌트 다이어그램은 정적 구조 다이어그램이다.\n\n**보충 개념**\nUML 다이어그램은 크게 구조 다이어그램과 행위 다이어그램으로 나뉜다.',
   'UML 다이어그램', 2, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'XP(Extreme Programming)의 다섯 가지 핵심 가치로 보기 어려운 것은?\n\n① 용기(Courage)\n② 존중(Respect)\n③ 정량 설계(Quantitative Design)\n④ 피드백(Feedback)', 'MCQ', 3, '정답: 3. XP의 핵심 가치는 의사소통, 단순성, 피드백, 용기, 존중이며 정량 설계는 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 용기는 XP의 핵심 가치이다.\n- 2번: 존중은 XP의 핵심 가치이다.\n- 3번: 정량 설계는 XP의 다섯 가지 핵심 가치에 들지 않는다.\n- 4번: 피드백은 XP의 핵심 가치이다.\n\n**보충 개념**\nXP는 짧은 반복 주기, 테스트 중심 개발, 고객 참여를 강조하는 애자일 방법론이다.',
   'XP', 1, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '자료 흐름도(DFD)의 구성 요소로 보기 어려운 것은?\n\n① Process\n② Data Flow\n③ Data Store\n④ Cardinality', 'MCQ', 4, '정답: 4. Cardinality는 개체 사이 관계의 대응 수를 의미하는 데이터 모델링 용어이며 DFD 구성 요소에 해당하지 않는다.\n\n**오답 풀이**\n- 1번: Process는 DFD의 구성 요소이다.\n- 2번: Data Flow는 DFD의 구성 요소이다.\n- 3번: Data Store는 DFD의 구성 요소이다.\n- 4번: Cardinality는 DFD의 구성 요소가 아니다.\n\n**보충 개념**\nDFD의 기본 구성 요소는 프로세스, 자료 흐름, 자료 저장소, 단말이다.',
   'DFD', 1, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '모바일 제스처(Mobile Gesture)의 종류로 보기 어려운 것은?\n\n① Tap\n② Drag\n③ Flick\n④ Flow', 'MCQ', 4, '정답: 4. Flow는 일반적인 모바일 제스처 명칭으로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: Tap은 화면을 짧게 누르는 제스처이다.\n- 2번: Drag는 누른 상태로 끌어 이동하는 제스처이다.\n- 3번: Flick은 빠르게 튕기듯 움직이는 제스처이다.\n- 4번: Flow는 모바일 제스처로 보기 어렵다.\n\n**보충 개념**\n대표적인 모바일 제스처에는 Tap, Double Tap, Drag, Flick, Pinch, Swipe 등이 있다.',
   '모바일 제스처', 1, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '미들웨어(Middleware) 종류 중 메시지 기반의 비동기 통신을 제공하는 방식은?\n\n① RPC\n② MOM\n③ ORB\n④ WAS', 'MCQ', 2, '정답: 2. MOM(Message Oriented Middleware)은 메시지 큐를 활용한 비동기 통신을 지원하는 미들웨어이다.\n\n**오답 풀이**\n- 1번: RPC는 원격 프로시저 호출 방식이다.\n- 2번: MOM은 메시지 기반의 비동기 통신을 지원한다.\n- 3번: ORB는 객체 사이의 통신을 중개한다.\n- 4번: WAS는 웹 애플리케이션 실행 환경을 제공한다.\n\n**보충 개념**\nMOM은 송신자와 수신자가 동시에 연결되어 있지 않아도 메시지 큐를 통해 통신할 수 있다.',
   'MOM', 1, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '컴포넌트 설계에서 협약(Contract)에 의한 설계의 조건으로 보기 어려운 것은?\n\n① 선행 조건(Precondition)\n② 결과 조건(Postcondition)\n③ 불변 조건(Invariant)\n④ 외부 조건(External condition)', 'MCQ', 4, '정답: 4. 계약에 의한 설계의 주요 조건은 선행 조건, 결과 조건, 불변 조건이며 외부 조건은 대표 조건에 들지 않는다.\n\n**오답 풀이**\n- 1번: 선행 조건은 실행 전 만족해야 하는 조건이다.\n- 2번: 결과 조건은 실행 후 보장되어야 하는 조건이다.\n- 3번: 불변 조건은 실행 전후에 항상 유지되어야 하는 조건이다.\n- 4번: 외부 조건은 계약에 의한 설계의 대표 조건이 아니다.\n\n**보충 개념**\n계약에 의한 설계는 컴포넌트가 제공해야 할 책임과 조건을 명확히 정의한다.',
   '계약에 의한 설계', 2, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '시스템의 기본 요소 중 처리 결과가 기대치에 미치지 못했을 때 그 결과를 다시 입력으로 되돌리는 과정은?\n\n① 입력(Input)\n② 출력(Output)\n③ 피드백(Feedback)\n④ 제어(Control)', 'MCQ', 3, '정답: 3. 피드백은 출력 결과를 다시 입력이나 조정 정보로 되돌려 시스템을 개선해 나가는 과정이다.\n\n**오답 풀이**\n- 1번: 입력은 시스템에 투입되는 자료나 자원이다.\n- 2번: 출력은 처리의 결과이다.\n- 3번: 피드백은 결과를 되돌려 조정하는 과정이다.\n- 4번: 제어는 목표 달성을 위해 시스템 동작을 조정하는 기능이다.\n\n**보충 개념**\n시스템은 입력, 처리, 출력, 제어, 피드백 요소로 구성된다고 설명할 수 있다.',
   '시스템 요소', 1, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '기업 내 애플리케이션 통합(EAI) 구축 유형 중 중앙의 허브를 두고 데이터를 전송하는 방식은?\n\n① Point-to-Point\n② Hub-and-Spoke\n③ Message Bus\n④ Hybrid', 'MCQ', 2, '정답: 2. Hub-and-Spoke 방식은 중앙 허브를 매개로 각 시스템을 연결하고 데이터를 중계한다.\n\n**오답 풀이**\n- 1번: Point-to-Point는 시스템 사이를 1:1로 직접 연결하는 방식이다.\n- 2번: Hub-and-Spoke는 중앙 허브를 사용한다.\n- 3번: Message Bus는 공통 메시지 버스를 통해 시스템을 연결한다.\n- 4번: Hybrid는 여러 방식을 조합한 형태이다.\n\n**보충 개념**\nEAI는 기업 내 다양한 애플리케이션을 연계하여 데이터와 프로세스를 통합한다.',
   'EAI', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '사용자가 소프트웨어를 얼마나 쉽게 배우고 편리하게 사용할 수 있는지를 나타내는 품질 특성은?\n\n① 가용성(Availability)\n② 사용성(Usability)\n③ 신뢰성(Reliability)\n④ 무결성(Integrity)', 'MCQ', 2, '정답: 2. 사용성은 사용자가 소프트웨어를 쉽게 이해하고 배우며 사용할 수 있는 정도를 나타낸다.\n\n**오답 풀이**\n- 1번: 가용성은 시스템이 사용 가능한 정도를 의미한다.\n- 2번: 사용성은 사용 편의성과 학습 용이성을 포함한다.\n- 3번: 신뢰성은 일정 조건에서 고장 없이 동작하는 정도이다.\n- 4번: 무결성은 데이터의 정확성과 일관성 유지와 관련된다.\n\n**보충 개념**\n사용성은 사용자 인터페이스와 사용자 경험 품질에 큰 영향을 끼친다.',
   '소프트웨어 품질', 1, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '나선형(Spiral) 모델의 4단계 순서로 알맞은 것은?\n\n① 계획 → 위험분석 → 개발 → 고객평가\n② 계획 → 개발 → 위험분석 → 보수\n③ 분석 → 설계 → 구현 → 테스트\n④ 요구분석 → 위험분석 → 설계 → 평가', 'MCQ', 1, '정답: 1. 나선형 모델은 계획, 위험 분석, 개발 및 검증, 고객 평가의 사이클을 반복한다.\n\n**오답 풀이**\n- 1번: 나선형 모델의 대표적인 단계 순서이다.\n- 2번: 위험 분석이 개발 이후에 배치되어 부적절하다.\n- 3번: 일반적인 개발 단계 순서에 가깝다.\n- 4번: 나선형 모델의 표준 단계 표현과 어긋난다.\n\n**보충 개념**\n나선형 모델은 위험 분석을 핵심으로 하며 대규모·복잡한 프로젝트에 적합하다.',
   '나선형 모델', 1, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '폭포수(Waterfall) 모델에 대한 설명으로 알맞은 것은?\n\n① 단계를 산출물이 명확하며 메뉴얼 작성이 필수적이다.\n② 개발 도중 요구사항 변경이 용이하다.\n③ 시제품을 만들어 고객의 피드백을 수시로 받는다.\n④ 위험 분석 단계를 통해 프로젝트 실패 가능성을 낮춘다.', 'MCQ', 1, '정답: 1. 폭포수 모델은 각 단계의 산출물이 분명하고 문서화가 중요한 모델이다.\n\n**오답 풀이**\n- 1번: 폭포수 모델은 각 단계의 산출물을 토대로 다음 단계로 넘어간다.\n- 2번: 폭포수 모델은 개발 중 요구사항 변경에 유연하지 않다.\n- 3번: 시제품 중심의 진행은 프로토타입 모델의 특징이다.\n- 4번: 위험 분석 반복은 나선형 모델의 특징이다.\n\n**보충 개념**\n폭포수 모델은 요구분석, 설계, 구현, 테스트, 유지보수 순으로 진행되는 전통적 개발 모델이다.',
   '폭포수 모델', 2, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 개발 표준 중 프로젝트 관리와 품질 보증을 위한 국제 표준은?\n\n① ISO/IEC 12207\n② ISO/IEC 15504(SPICE)\n③ CMMI\n④ IEEE 802.11', 'MCQ', 1, '정답: 1. ISO/IEC 12207은 소프트웨어 생명주기 프로세스를 정의하는 국제 표준으로 프로젝트 관리와 품질 보증 활동을 포함한다.\n\n**오답 풀이**\n- 1번: ISO/IEC 12207은 소프트웨어 생명주기 프로세스 국제 표준이다.\n- 2번: ISO/IEC 15504는 프로세스 평가 표준이다.\n- 3번: CMMI는 조직 프로세스 성숙도 모델이다.\n- 4번: IEEE 802.11은 무선 LAN 표준이다.\n\n**보충 개념**\n소프트웨어 표준은 개발 프로세스의 일관성과 품질 확보에 도움을 준다.',
   '소프트웨어 표준', 2, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '형상 관리(Configuration Management)의 절차 중 형상 항목의 변경을 검토하고 승인하는 단계는?\n\n① 형상 식별\n② 형상 통제\n③ 형상 감사\n④ 형상 기록', 'MCQ', 2, '정답: 2. 형상 통제는 변경 요청을 검토하고 승인 여부를 결정해 변경을 관리하는 활동이다.\n\n**오답 풀이**\n- 1번: 형상 식별은 관리 대상 항목을 식별하는 단계이다.\n- 2번: 형상 통제는 변경 검토와 승인을 담당한다.\n- 3번: 형상 감사는 형상 항목이 요구사항에 부합하는지 확인한다.\n- 4번: 형상 기록은 상태 보고와 이력 관리에 가깝다.\n\n**보충 개념**\n형상 관리는 산출물의 변경과 버전을 체계적으로 통제한다.',
   '형상 관리', 2, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '객체지향 기법에서 데이터와 연산을 하나로 묶고 내부 구현 내용을 외부로부터 감추는 것은?\n\n① 상속(Inheritance)\n② 다형성(Polymorphism)\n③ 캡슐화(Encapsulation)\n④ 추상화(Abstraction)', 'MCQ', 3, '정답: 3. 캡슐화는 데이터와 메서드를 하나로 묶고 내부 구현을 외부로부터 감추는 객체지향 특성이다.\n\n**오답 풀이**\n- 1번: 상속은 상위 클래스의 특성을 하위 클래스가 물려받는 것이다.\n- 2번: 다형성은 같은 메시지에 대해 객체별로 다르게 반응하는 특성이다.\n- 3번: 캡슐화는 데이터와 연산을 묶고 정보를 은닉한다.\n- 4번: 추상화는 핵심 속성과 행위를 일반화하는 것이다.\n\n**보충 개념**\n캡슐화는 정보 은닉과 함께 유지보수성과 안정성을 높여 준다.',
   '캡슐화', 1, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 공학의 기본 원칙과 가장 거리가 먼 것은?\n\n① 품질이 높은 소프트웨어 제작\n② 개발 비용의 최소화\n③ 문서화의 배제 및 코드 위주 개발\n④ 개발 기간의 단축', 'MCQ', 3, '정답: 3. 소프트웨어 공학은 체계적 개발과 문서화를 중시하므로 문서화를 배제하는 것은 기본 원칙과 거리가 멀다.\n\n**오답 풀이**\n- 1번: 품질 향상은 소프트웨어 공학의 목적이다.\n- 2번: 개발 비용 절감은 소프트웨어 공학의 목적이다.\n- 3번: 문서화 배제는 소프트웨어 공학의 원칙이 아니다.\n- 4번: 개발 기간 단축은 소프트웨어 공학의 기대 효과이다.\n\n**보충 개념**\n소프트웨어 공학은 개발, 운영, 유지보수에 공학적 원리를 적용하여 품질과 생산성을 높인다.',
   '소프트웨어 공학', 1, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '통합 테스트 기법 중 하위 모듈에서 상위 모듈로 통합하면서, 데이터 전달을 위해 드라이버(Driver)가 필요한 방식은?\n\n① 하향식 통합 테스트\n② 상향식 통합 테스트\n③ 빅뱅 테스트\n④ 백병 테스트', 'MCQ', 2, '정답: 2. 상향식 통합 테스트는 하위 모듈부터 통합하면서 상위 모듈 역할을 대신할 드라이버를 필요로 한다.\n\n**오답 풀이**\n- 1번: 하향식 통합 테스트는 스텁이 필요하다.\n- 2번: 상향식 통합 테스트는 드라이버가 필요하다.\n- 3번: 빅뱅 테스트는 모든 모듈을 한 번에 통합한다.\n- 4번: 백병 테스트는 표준적인 통합 테스트 용어가 아니다.\n\n**보충 개념**\n통합 테스트에서는 모듈 간 인터페이스와 데이터 흐름을 함께 검증한다.',
   '통합 테스트', 2, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '알고리즘의 시간 복잡도 표기 중 입력 데이터 양과 무관하게 실행 시간이 일정한 경우의 표기는?\n\n① O(1)\n② O(n)\n③ O(log n)\n④ O(n^2)', 'MCQ', 1, '정답: 1. O(1)은 입력 크기와 관계없이 일정한 시간이 걸리는 상수 시간 복잡도를 의미한다.\n\n**오답 풀이**\n- 1번: O(1)은 상수 시간 복잡도이다.\n- 2번: O(n)은 입력 크기에 비례한다.\n- 3번: O(log n)은 로그 형태로 증가한다.\n- 4번: O(n^2)은 입력 크기의 제곱에 비례한다.\n\n**보충 개념**\n배열 인덱스 접근처럼 입력 크기와 관계없이 한 번에 처리되는 연산은 O(1)에 해당한다.',
   '시간 복잡도', 1, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 테스트의 원리 중 전체 결함의 80%가 전체 모듈의 약 20%에서 집중적으로 발생한다는 법칙은?\n\n① 살충제 패러독스\n② 파레토 법칙\n③ 브룩스의 법칙\n④ 오류 부재의 궤변', 'MCQ', 2, '정답: 2. 결과의 80%가 원인의 20%에서 발생한다는 원리를 파레토 법칙이라고 한다.\n\n**오답 풀이**\n- 1번: 살충제 패러독스는 같은 테스트를 반복하면 새 결함을 찾기 어려워진다는 현상이다.\n- 2번: 파레토 법칙은 80:20 원리이다.\n- 3번: 브룩스의 법칙은 인력 추가와 일정 지연에 관한 법칙이다.\n- 4번: 오류 부재의 궤변은 결함이 없어도 요구를 만족하지 못하면 품질이 낮다는 개념이다.\n\n**보충 개념**\n테스트에서는 결함이 집중되는 영역을 우선적으로 관리해야 한다.',
   '파레토 법칙', 1, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '개발자의 개입 없이 사용자가 자신의 환경에서 직접 수행하는 테스트는?\n\n① 알파 테스트\n② 베타 테스트\n③ 단위 테스트\n④ 회귀 테스트', 'MCQ', 2, '정답: 2. 베타 테스트는 실제 사용자가 자신의 환경에서 제품을 사용하면서 결함을 확인하는 테스트이다.\n\n**오답 풀이**\n- 1번: 알파 테스트는 개발 장소에서 사용자와 개발자가 함께 수행한다.\n- 2번: 베타 테스트는 실제 사용자 환경에서 진행된다.\n- 3번: 단위 테스트는 개별 모듈을 검증한다.\n- 4번: 회귀 테스트는 변경 후 기존 기능에 미친 영향을 확인한다.\n\n**보충 개념**\n인수 테스트는 알파 테스트와 베타 테스트를 포함할 수 있다.',
   '베타 테스트', 1, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 구조를 갖는 이진 트리를 전위 순회(Preorder Traversal)했을 때의 방문 순서로 알맞은 것은?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="420" height="230" viewBox="0 0 420 230" role="img" aria-label="이진 트리"><style>.node{fill:#fff;stroke:#333;stroke-width:2}.edge{stroke:#333;stroke-width:2}.txt{font-size:16px;font-family:Arial,sans-serif;text-anchor:middle;dominant-baseline:middle}</style><line x1="210" y1="35" x2="135" y2="90" class="edge"/><line x1="210" y1="35" x2="285" y2="90" class="edge"/><line x1="135" y1="90" x2="80" y2="150" class="edge"/><line x1="135" y1="90" x2="185" y2="150" class="edge"/><line x1="285" y1="90" x2="330" y2="150" class="edge"/><line x1="330" y1="150" x2="365" y2="200" class="edge"/><circle cx="210" cy="35" r="22" class="node"/><text x="210" y="35" class="txt">A</text><circle cx="135" cy="90" r="22" class="node"/><text x="135" y="90" class="txt">B</text><circle cx="285" cy="90" r="22" class="node"/><text x="285" y="90" class="txt">E</text><circle cx="80" cy="150" r="22" class="node"/><text x="80" y="150" class="txt">C</text><circle cx="185" cy="150" r="22" class="node"/><text x="185" y="150" class="txt">D</text><circle cx="330" cy="150" r="22" class="node"/><text x="330" y="150" class="txt">F</text><circle cx="365" cy="200" r="22" class="node"/><text x="365" y="200" class="txt">G</text></svg>\n\n① C-D-B-G-F-E-A\n② A-B-C-D-E-F-G\n③ B-C-D-A-E-F-G\n④ A-B-E-C-D-F-G', 'MCQ', 2, '정답: 2. 전위 순회는 루트 → 왼쪽 서브트리 → 오른쪽 서브트리 순서이므로 결과는 A-B-C-D-E-F-G가 된다.\n\n**오답 풀이**\n- 1번: 루트를 마지막에 방문하므로 전위 순회가 아니다.\n- 2번: 전위 순회 결과와 일치한다.\n- 3번: 루트 A를 가장 먼저 방문하지 않았다.\n- 4번: 왼쪽 서브트리와 오른쪽 서브트리의 방문 순서가 맞지 않는다.\n\n**보충 개념**\n이진 트리 순회에는 전위, 중위, 후위 순회가 있으며 전위 순회는 Root → Left → Right 순서이다.',
   '트리 순회', 3, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 설계에서 지향해야 할 방향으로 알맞은 것은?\n\n① 결합도는 높이고, 응집도는 낮춘다.\n② 결합도는 낮추고, 응집도는 높인다.\n③ 결합도와 응집도 모두 높인다.\n④ 결합도와 응집도 모두 낮춘다.', 'MCQ', 2, '정답: 2. 좋은 소프트웨어 설계는 모듈 간 결합도를 낮추고 모듈 내부의 응집도를 높이는 방향을 지향한다.\n\n**오답 풀이**\n- 1번: 결합도를 높이고 응집도를 낮추는 것은 바람직하지 않은 설계이다.\n- 2번: 결합도는 낮추고 응집도는 높이는 것이 바람직하다.\n- 3번: 결합도가 높으면 변경의 영향이 커진다.\n- 4번: 응집도가 낮으면 모듈의 책임이 모호해진다.\n\n**보충 개념**\n낮은 결합도와 높은 응집도는 유지보수성과 재사용성을 높여 준다.',
   '설계 품질', 1, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '제품 소프트웨어 패키징 시 고려사항으로 옳지 않은 것은?\n\n① 사용자 편의성을 고려한 설치 프로그램 제공\n② 하드웨어 환경 및 OS의 호환성 확인\n③ 버전 관리를 위한 릴리즈 노트 작성\n④ 소스코드의 전체 공개 원칙 준수', 'MCQ', 4, '정답: 4. 제품 패키징에서 소스코드 전체 공개가 항상 원칙으로 요구되는 것은 아니다.\n\n**오답 풀이**\n- 1번: 설치 편의성은 패키징 시 고려해야 할 요소이다.\n- 2번: 하드웨어와 OS 호환성을 사전에 확인해야 한다.\n- 3번: 릴리즈 노트는 버전과 변경 내용을 관리하는 데 필요하다.\n- 4번: 소스코드 전체 공개는 일반적인 패키징 고려사항이 아니다.\n\n**보충 개념**\n패키징은 사용자가 제품을 손쉽게 설치하고 사용할 수 있도록 구성하는 활동이다.',
   '소프트웨어 패키징', 1, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 재공학(Re-engineering) 활동 중 기존 코드를 분석해 설계 정보를 추출하는 과정은?\n\n① 역공학(Reverse Engineering)\n② 재구성(Restructuring)\n③ 이식(Migration)\n④ 분석(Analysis)', 'MCQ', 1, '정답: 1. 역공학은 기존 시스템이나 코드로부터 설계 정보, 구조, 명세를 추출하는 활동이다.\n\n**오답 풀이**\n- 1번: 역공학은 기존 코드에서 정보를 추출한다.\n- 2번: 재구성은 기능 변경 없이 내부 구조를 개선하는 활동이다.\n- 3번: 이식은 다른 운영 환경으로 옮기는 활동이다.\n- 4번: 분석은 일반적인 검토 활동이다.\n\n**보충 개념**\n재공학은 분석, 재구성, 역공학, 이식 등의 활동을 포함한다.',
   '역공학', 1, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'ISO/IEC 25010의 품질 특성 중 명시된 조건에서 사용될 때 규정된 기능을 수행할 수 있는 정도를 의미하는 것은?\n\n① 기능성(Functionality)\n② 효율성(Efficiency)\n③ 유지보수성(Maintainability)\n④ 이식성(Portability)', 'MCQ', 1, '정답: 1. 기능성은 명시된 조건에서 요구된 기능을 제공하는 정도를 의미한다.\n\n**오답 풀이**\n- 1번: 기능성은 요구 기능 수행 능력과 관련된다.\n- 2번: 효율성은 자원 사용 대비 성능과 관련된다.\n- 3번: 유지보수성은 수정과 개선의 용이성을 의미한다.\n- 4번: 이식성은 다른 환경으로 옮겨 사용할 수 있는 정도이다.\n\n**보충 개념**\nISO/IEC 25010은 소프트웨어 제품의 품질 특성을 체계적으로 정의한다.',
   'ISO/IEC 25010', 1, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'McCabe의 순환 복잡도(Cyclomatic Complexity) 계산식으로 알맞은 것은? (E: 간선 수, N: 노드 수)\n\n① V(G) = E - N + 2\n② V(G) = E + N - 2\n③ V(G) = N - E + 2\n④ V(G) = E - N + 1', 'MCQ', 1, '정답: 1. 순환 복잡도는 일반적으로 V(G) = E - N + 2로 계산한다.\n\n**오답 풀이**\n- 1번: McCabe 순환 복잡도의 표준 공식이다.\n- 2번: 간선과 노드 수를 더하는 식은 적절하지 않다.\n- 3번: E와 N의 위치가 반대로 되어 있다.\n- 4번: 단일 연결 그래프 기준 공식과 다르다.\n\n**보충 개념**\n순환 복잡도는 프로그램의 독립 경로 수를 나타내며 테스트 케이스 수를 산정하는 데 활용된다.',
   '순환 복잡도', 2, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '정렬 알고리즘 중 평균 시간 복잡도가 O(n log n)이 아닌 것은?\n\n① 퀵 정렬\n② 병합 정렬\n③ 힙 정렬\n④ 거품 정렬', 'MCQ', 4, '정답: 4. 거품 정렬의 평균 시간 복잡도는 O(n²)이다.\n\n**오답 풀이**\n- 1번: 퀵 정렬의 평균 시간 복잡도는 O(n log n)이다.\n- 2번: 병합 정렬의 시간 복잡도는 O(n log n)이다.\n- 3번: 힙 정렬의 시간 복잡도는 O(n log n)이다.\n- 4번: 거품 정렬은 평균 O(n²)이다.\n\n**보충 개념**\n버블, 선택, 삽입 같은 단순 정렬은 일반적으로 O(n²)에 해당한다.',
   '정렬', 2, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '나중에 들어온 데이터가 먼저 나가는 LIFO(Last-In-First-Out) 구조의 자료구조는?\n\n① Queue\n② Stack\n③ Linked List\n④ Tree', 'MCQ', 2, '정답: 2. Stack은 나중에 들어온 데이터가 먼저 나가는 LIFO 구조이다.\n\n**오답 풀이**\n- 1번: Queue는 FIFO 구조이다.\n- 2번: Stack은 LIFO 구조이다.\n- 3번: Linked List는 노드를 연결한 자료 구조이다.\n- 4번: Tree는 비선형 계층 구조이다.\n\n**보충 개념**\n스택은 함수 호출 관리, 괄호 검사, 후위 표기식 계산 등에 활용된다.',
   '스택', 1, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '큐(Queue)의 활용 사례로 가장 적절한 것은?\n\n① 재귀 호출의 복귀 주소 저장\n② 후위 표기법 연산\n③ 운영체제의 작업 스케줄링(대기 행렬)\n④ 수식의 괄호 검사', 'MCQ', 3, '정답: 3. 큐는 먼저 들어온 작업을 먼저 처리하는 대기 행렬에 적합하다.\n\n**오답 풀이**\n- 1번: 재귀 호출의 복귀 주소 저장은 스택이 담당한다.\n- 2번: 후위 표기법 연산에는 스택이 사용된다.\n- 3번: 작업 대기열은 큐의 대표적인 활용 사례이다.\n- 4번: 괄호 검사는 스택을 활용한다.\n\n**보충 개념**\n큐는 FIFO 구조이며 작업 대기열, 버퍼, BFS 등에 사용된다.',
   '큐', 1, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '블랙박스 테스트 기법 중 입력 조건의 경계 부근에서 오류 발생 확률이 높다는 점을 이용한 기법은?\n\n① 동등 분할 테스트\n② 경계값 분석 테스트\n③ 원인-결과 그래프 테스트\n④ 비교 테스트', 'MCQ', 2, '정답: 2. 경계값 분석 테스트는 입력 범위의 경계값 부근에서 오류가 자주 발생한다는 점을 이용한다.\n\n**오답 풀이**\n- 1번: 동등 분할은 입력 영역을 동등한 그룹으로 나누어 테스트한다.\n- 2번: 경계값 분석은 경계 부근의 값들을 집중적으로 테스트한다.\n- 3번: 원인-결과 그래프는 입력 조건과 출력 결과 관계를 분석한다.\n- 4번: 비교 테스트는 여러 구현의 결과를 비교한다.\n\n**보충 개념**\n블랙박스 테스트는 내부 구조를 보지 않고 입력과 출력 관점에서 검사한다.',
   '경계값 분석', 1, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '화이트박스 테스트에 대한 설명으로 옳지 않은 것은?\n\n① 소스코드의 모든 문장을 한 번 이상 실행한다.\n② 모듈의 내부 로직을 직접 관찰한다.\n③ 출력 결과가 사전에 정의된 결과와 일치하는지만 확인한다.\n④ 제어 구조 및 조건 분기를 검사한다.', 'MCQ', 3, '정답: 3. 출력 결과만 확인하는 방식은 블랙박스 테스트 관점에 가깝다.\n\n**오답 풀이**\n- 1번: 문장 검사는 화이트박스 테스트의 일부이다.\n- 2번: 내부 로직 관찰은 화이트박스 테스트의 특징이다.\n- 3번: 출력 결과 중심의 확인은 블랙박스 테스트에 가깝다.\n- 4번: 제어 구조와 조건 분기 검사는 화이트박스 테스트에 해당한다.\n\n**보충 개념**\n화이트박스 테스트는 코드의 경로, 조건, 루프, 분기 구조를 기준으로 진행한다.',
   '화이트박스 테스트', 1, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '테스트 하네스 구성 요소 중 하위 모듈이 호출되었을 때 가상의 결과를 반환해 주는 더미 모듈은?\n\n① Driver\n② Stub\n③ Oracle\n④ Monitor', 'MCQ', 2, '정답: 2. Stub은 아직 구현되지 않았거나 테스트 대상 하위 모듈을 대신해 가상의 결과를 반환하는 더미 모듈이다.\n\n**오답 풀이**\n- 1번: Driver는 테스트 대상 모듈을 호출하는 상위 모듈 역할을 한다.\n- 2번: Stub은 하위 모듈을 대체한다.\n- 3번: Oracle은 테스트 결과의 참·거짓 판단 기준 역할을 한다.\n- 4번: Monitor는 테스트 실행 상태를 관찰하는 도구이다.\n\n**보충 개념**\n하향식 통합 테스트에서는 스텁이, 상향식 통합 테스트에서는 드라이버가 주로 사용된다.',
   '테스트 하네스', 1, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '완전 이진 트리의 높이가 4일 때 최대 노드의 개수는?\n\n① 7개\n② 15개\n③ 31개\n④ 63개', 'MCQ', 2, '정답: 2. 높이가 4인 완전 이진 트리의 최대 노드 수는 2^4 - 1 = 15개이다.\n\n**오답 풀이**\n- 1번: 높이 3일 때의 최대 노드 수이다.\n- 2번: 높이 4일 때의 최대 노드 수이다.\n- 3번: 높이 5일 때의 최대 노드 수이다.\n- 4번: 높이 6일 때의 최대 노드 수이다.\n\n**보충 개념**\n높이가 h인 포화 이진 트리의 최대 노드 수는 2^h - 1로 계산한다.',
   '이진 트리', 2, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소스코드를 실행하지 않고 결함을 찾아내는 정적 분석 도구의 특징으로 보기 어려운 것은?\n\n① 코딩 표준 준수 여부 확인\n② 복잡도 분석\n③ 실제 데이터 입력에 의한 실행 결과 확인\n④ 결함 빈도 확인', 'MCQ', 3, '정답: 3. 실제 데이터를 입력해 실행 결과를 확인하는 방식은 동적 테스트에 해당한다.\n\n**오답 풀이**\n- 1번: 정적 분석은 코딩 표준 위반을 확인할 수 있다.\n- 2번: 정적 분석은 복잡도를 측정할 수 있다.\n- 3번: 실행 결과 확인은 정적 분석의 특징이 아니다.\n- 4번: 정적 분석으로 결함의 유형과 빈도를 확인할 수 있다.\n\n**보충 개념**\n정적 분석은 소스코드를 실행하지 않고 코드 구조와 규칙 위반 여부를 검사한다.',
   '정적 분석', 1, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '빌드 자동화 도구 중 자바 기반의 오픈 소스로 가장 널리 사용되는 것은?\n\n① Jenkins\n② Gradle\n③ Maven\n④ Ant', 'MCQ', 1, '정답: 1. Jenkins는 자바 기반의 오픈소스 자동화 서버로, 빌드·테스트·배포 자동화에 폭넓게 사용된다.\n\n**오답 풀이**\n- 1번: Jenkins는 대표적인 빌드 자동화 및 CI 도구이다.\n- 2번: Gradle은 빌드 도구이지만 문제에서 묻는 ‘널리 사용되는 자바 기반 오픈소스 자동화 서버’의 대표 답은 Jenkins이다.\n- 3번: Maven은 자바 프로젝트의 빌드와 의존성 관리를 담당한다.\n- 4번: Ant는 자바 기반의 빌드 도구이다.\n\n**보충 개념**\n빌드 자동화 도구는 소스 컴파일, 테스트, 패키징, 배포 과정을 자동화한다.',
   'Jenkins', 1, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '인스펙션(Inspection) 프로세스의 진행 단계가 순서대로 나열된 것은?\n\n① 계획-준비-회의-수정-확인\n② 회의-계획-수정-준비-확인\n③ 계획-회의-준비-확인-수정\n④ 준비-계획-회의-확인-수정', 'MCQ', 1, '정답: 1. 인스펙션은 보통 계획, 준비, 회의, 수정, 확인의 순서로 진행된다.\n\n**오답 풀이**\n- 1번: 올바른 인스펙션 진행 순서이다.\n- 2번: 회의가 계획보다 먼저 올 수는 없다.\n- 3번: 준비는 회의보다 먼저 수행되어야 한다.\n- 4번: 계획은 준비보다 먼저 수행되어야 한다.\n\n**보충 개념**\n인스펙션은 산출물을 체계적으로 검토해 결함을 조기에 발견하는 정적 테스트 활동이다.',
   '인스펙션', 2, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'SQL 명령 중 DDL(데이터 정의어)에 해당하는 것은?\n\n① SELECT\n② UPDATE\n③ ALTER\n④ INSERT', 'MCQ', 3, '정답: 3. ALTER는 테이블 등 데이터베이스 객체의 구조를 변경하는 DDL 명령이다.\n\n**오답 풀이**\n- 1번: SELECT는 DML이다.\n- 2번: UPDATE는 DML이다.\n- 3번: ALTER는 DDL이다.\n- 4번: INSERT는 DML이다.\n\n**보충 개념**\nDDL의 대표 명령으로 CREATE, ALTER, DROP, TRUNCATE 등이 있다.',
   'DDL', 1, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '''학생'' 테이블의 ''주소'' 컬럼을 삭제하면서, 그 컬럼을 참조하는 다른 객체들까지 연쇄적으로 삭제하는 명령은?\n\n① ALTER TABLE 학생 DROP COLUMN 주소 RESTRICT;\n② ALTER TABLE 학생 DROP COLUMN 주소 CASCADE;\n③ DELETE FROM 학생 WHERE 컬럼 = ''주소'';\n④ DROP TABLE 학생;', 'MCQ', 2, '정답: 2. CASCADE 옵션은 삭제 대상과 관련된 참조 객체까지 함께 삭제하도록 한다.\n\n**오답 풀이**\n- 1번: RESTRICT는 참조하는 객체가 있으면 삭제를 제한한다.\n- 2번: CASCADE는 연쇄 삭제를 수행한다.\n- 3번: DELETE는 행을 삭제하는 명령이지 컬럼을 삭제하지 않는다.\n- 4번: DROP TABLE은 테이블 자체를 삭제한다.\n\n**보충 개념**\nALTER TABLE의 DROP COLUMN은 특정 컬럼을 제거할 때 사용한다.',
   'ALTER TABLE', 2, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'SQL에서 이름에 ''길''이 포함된 모든 데이터를 조회하는 조건절로 알맞은 것은?\n\n① WHERE 이름 = ''길%''\n② WHERE 이름 LIKE ''%길%''\n③ WHERE 이름 LIKE ''길_''\n④ WHERE 이름 IN (''길'')', 'MCQ', 2, '정답: 2. 문자열 중간에 특정 문자가 포함된 데이터를 찾을 때는 LIKE와 양쪽 `%` 와일드카드를 함께 사용한다.\n\n**오답 풀이**\n- 1번: `=`는 와일드카드 패턴 매칭을 수행하지 않는다.\n- 2번: `%길%`은 이름에 ‘길’이 포함된 모든 값을 찾는다.\n- 3번: `길_`은 ‘길’로 시작하고 뒤에 한 글자가 있는 값만 찾는다.\n- 4번: IN은 지정된 값과 정확히 일치하는지 확인한다.\n\n**보충 개념**\nLIKE에서 `%`는 0개 이상의 임의 문자를, `_`는 한 글자를 의미한다.',
   'LIKE', 1, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '제1정규형(1NF)에서 제2정규형(2NF)으로 가기 위한 조건은?\n\n① 다중값 속성 제거\n② 부분 함수적 종속 제거\n③ 이행적 함수적 종속 제거\n④ 결정자가 후보키가 아닌 함수 종속 제거', 'MCQ', 2, '정답: 2. 제2정규형은 제1정규형을 만족하면서 부분 함수 종속을 제거한 정규형이다.\n\n**오답 풀이**\n- 1번: 다중값 속성 제거는 제1정규형과 관련된다.\n- 2번: 부분 함수 종속 제거는 제2정규형의 핵심이다.\n- 3번: 이행적 함수 종속 제거는 제3정규형과 관련된다.\n- 4번: 결정자가 후보키가 아닌 함수 종속 제거는 BCNF와 관련된다.\n\n**보충 개념**\n정규화는 데이터의 중복과 이상 현상을 줄이기 위한 과정이다.',
   '제2정규형', 2, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '기본키(Primary Key)의 값은 NULL이 될 수 없으며 중복될 수도 없다는 무결성 원칙은?\n\n① 개체 무결성\n② 참조 무결성\n③ 도메인 무결성\n④ 사용자 정의 무결성', 'MCQ', 1, '정답: 1. 개체 무결성은 기본키가 NULL이거나 중복되어서는 안 된다는 원칙이다.\n\n**오답 풀이**\n- 1번: 개체 무결성은 기본키 제약과 관련된다.\n- 2번: 참조 무결성은 외래키와 참조 대상의 일관성을 보장한다.\n- 3번: 도메인 무결성은 속성값의 허용 범위를 제한한다.\n- 4번: 사용자 정의 무결성은 업무 규칙에 따른 제약이다.\n\n**보충 개념**\n기본키는 각 튜플을 유일하게 식별하기 위해 사용된다.',
   '개체 무결성', 1, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '관계 데이터 모델의 릴레이션(Relation)에 대한 설명으로 옳지 않은 것은?\n\n① 튜플(Tuple)을 사이에는 순서가 없다.\n② 모든 속성(Attribute) 값은 원자값이어야 한다.\n③ 한 릴레이션 내에 중복된 튜플이 존재할 수 있다.\n④ 속성들 사이에는 순서가 없다.', 'MCQ', 3, '정답: 3. 릴레이션에서는 동일한 튜플이 중복으로 존재할 수 없다.\n\n**오답 풀이**\n- 1번: 튜플 사이의 순서는 의미가 없다.\n- 2번: 속성값은 원자값이어야 한다.\n- 3번: 릴레이션은 중복 튜플을 허용하지 않는다.\n- 4번: 속성 사이의 순서 역시 의미가 없다.\n\n**보충 개념**\n릴레이션은 행인 튜플과 열인 속성으로 구성된 2차원 테이블 구조이다.',
   '릴레이션', 1, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '후보키 가운데 대표로 선정되어 NULL 값을 가질 수 없는 키는?\n\n① 슈퍼키\n② 외래키\n③ 기본키\n④ 대체키', 'MCQ', 3, '정답: 3. 기본키는 후보키 중에서 대표로 지정된 키이며 NULL 값을 가질 수 없다.\n\n**오답 풀이**\n- 1번: 슈퍼키는 유일성을 만족하는 속성 집합이다.\n- 2번: 외래키는 다른 릴레이션의 기본키를 참조하는 키이다.\n- 3번: 기본키는 후보키 중 대표로 선정된 키이다.\n- 4번: 대체키는 기본키로 선택되지 않은 후보키이다.\n\n**보충 개념**\n기본키는 유일성과 최소성을 만족하며 개체 무결성을 보장한다.',
   '기본키', 1, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'E-R 다이어그램의 구성 요소 중 개체(Entity)를 나타내는 기호는?\n\n① 타원\n② 사각형\n③ 마름모\n④ 화살표', 'MCQ', 2, '정답: 2. E-R 다이어그램에서 개체는 사각형으로 표현한다.\n\n**오답 풀이**\n- 1번: 타원은 속성을 나타낸다.\n- 2번: 사각형은 개체를 표현한다.\n- 3번: 마름모는 관계를 나타낸다.\n- 4번: 화살표는 관계의 방향이나 흐름을 표시할 때 활용될 수 있다.\n\n**보충 개념**\nE-R 다이어그램은 개체, 관계, 속성을 도형 기호로 표현한다.',
   'ERD', 1, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '트랜잭션의 특징 중 모든 연산이 데이터베이스에 전부 반영되거나 전혀 반영되지 않아야 한다는 성질은?\n\n① 원자성(Atomicity)\n② 일관성(Consistency)\n③ 격리성(Isolation)\n④ 영속성(Durability)', 'MCQ', 1, '정답: 1. 원자성은 트랜잭션의 모든 연산이 전부 수행되거나 전혀 수행되지 않아야 한다는 성질이다.\n\n**오답 풀이**\n- 1번: 원자성은 All or Nothing 성질을 의미한다.\n- 2번: 일관성은 트랜잭션 수행 전후로 데이터베이스가 일관된 상태를 유지하는 성질이다.\n- 3번: 격리성은 동시에 수행되는 트랜잭션 사이의 간섭을 막는 성질이다.\n- 4번: 영속성은 완료된 트랜잭션의 결과가 영구적으로 반영된다는 성질이다.\n\n**보충 개념**\n트랜잭션의 ACID는 원자성, 일관성, 격리성, 영속성의 머리글자이다.',
   'ACID', 1, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '두 테이블에서 공통된 속성을 매개로 데이터를 결합하는 연산 중, 조인 조건에 맞지 않는 행도 결과에 포함하는 조인은?\n\n① Inner Join\n② Natural Join\n③ Outer Join\n④ Cross Join', 'MCQ', 3, '정답: 3. Outer Join은 조인 조건에 맞지 않는 행도 NULL을 채워서 결과에 포함시킬 수 있다.\n\n**오답 풀이**\n- 1번: Inner Join은 조건에 맞는 행만 반환한다.\n- 2번: Natural Join은 공통 속성을 기준으로 자동 조인한다.\n- 3번: Outer Join은 조건이 맞지 않는 행도 포함할 수 있다.\n- 4번: Cross Join은 카티션 곱을 생성한다.\n\n**보충 개념**\nOuter Join은 Left, Right, Full Outer Join으로 세분화된다.',
   'Outer Join', 2, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '뷰(View)에 대한 설명으로 알맞은 것은?\n\n① 물리적으로 데이터를 저장하는 테이블이다.\n② 독자적인 인덱스를 가질 수 있다.\n③ 논리적 독립성을 제공하며 보안 관리에 유리하다.\n④ 뷰 위에 다른 뷰를 정의할 수 없다.', 'MCQ', 3, '정답: 3. 뷰는 논리적 가상 테이블로, 데이터 독립성과 보안성 향상에 활용된다.\n\n**오답 풀이**\n- 1번: 일반적인 뷰는 실제 데이터를 저장하지 않는다.\n- 2번: 뷰는 일반적으로 독자적인 인덱스를 갖지 않는다.\n- 3번: 뷰는 논리적 독립성과 보안성을 제공한다.\n- 4번: 뷰를 기반으로 또 다른 뷰를 정의할 수 있다.\n\n**보충 개념**\n뷰는 복잡한 질의를 단순화하고 사용자별 접근 범위를 제한할 수 있다.',
   '뷰', 2, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '트랜잭션 제어어(TCL) 중 작업 내용을 저장하고 트랜잭션을 종료하는 명령은?\n\n① ROLLBACK\n② COMMIT\n③ GRANT\n④ REVOKE', 'MCQ', 2, '정답: 2. COMMIT은 트랜잭션의 변경 내용을 확정하고 영구적으로 저장한다.\n\n**오답 풀이**\n- 1번: ROLLBACK은 트랜잭션의 변경 내용을 취소한다.\n- 2번: COMMIT은 작업 내용을 확정한다.\n- 3번: GRANT는 권한 부여 명령이다.\n- 4번: REVOKE는 권한 회수 명령이다.\n\n**보충 개념**\nTCL에는 COMMIT, ROLLBACK, SAVEPOINT 등이 있다.',
   'TCL', 1, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '사용자에게 특정 테이블에 대한 SELECT 권한을 부여하는 명령은?\n\n① GRANT SELECT ON 테이블 TO 사용자;\n② GIVE SELECT ON 테이블 TO 사용자;\n③ REVOKE SELECT ON 테이블 FROM 사용자;\n④ DENY SELECT ON 테이블 TO 사용자;', 'MCQ', 1, '정답: 1. GRANT는 사용자에게 권한을 부여하는 DCL 명령이다.\n\n**오답 풀이**\n- 1번: SELECT 권한을 부여하는 올바른 명령이다.\n- 2번: GIVE는 표준 SQL의 권한 부여 명령이 아니다.\n- 3번: REVOKE는 권한을 회수하는 명령이다.\n- 4번: DENY는 표준 SQL의 권한 부여 명령이 아니다.\n\n**보충 개념**\nDCL은 데이터 접근 권한을 제어하며 GRANT와 REVOKE가 대표적이다.',
   'GRANT', 1, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '정규화가 부족할 때 발생하는 이상(Anomaly) 현상으로 보기 어려운 것은?\n\n① 삽입 이상\n② 삭제 이상\n③ 갱신 이상\n④ 검색 이상', 'MCQ', 4, '정답: 4. 정규화 부족으로 발생하는 대표 이상 현상은 삽입, 삭제, 갱신 이상이다.\n\n**오답 풀이**\n- 1번: 삽입 이상은 대표적인 이상 현상이다.\n- 2번: 삭제 이상은 대표적인 이상 현상이다.\n- 3번: 갱신 이상은 대표적인 이상 현상이다.\n- 4번: 검색 이상은 일반적인 이상 현상 분류에 포함되지 않는다.\n\n**보충 개념**\n정규화는 데이터의 중복을 줄이고 이상 현상을 방지하기 위한 과정이다.',
   '이상 현상', 1, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '관계 대수 연산 중 릴레이션에서 특정 속성(열)들만 추출하는 연산은?\n\n① Select\n② Project\n③ Join\n④ Division', 'MCQ', 2, '정답: 2. Project는 릴레이션에서 지정한 속성만 추출하는 관계 대수 연산이다.\n\n**오답 풀이**\n- 1번: Select는 조건에 맞는 튜플을 추출한다.\n- 2번: Project는 특정 속성을 추출한다.\n- 3번: Join은 두 릴레이션을 결합한다.\n- 4번: Division은 나눗셈 형태의 관계 연산이다.\n\n**보충 개념**\n관계 대수에서 Select는 행 선택, Project는 열 선택에 해당한다.',
   '관계 대수', 1, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '분산 데이터베이스의 특징 중 사용자가 데이터의 물리적 위치를 알지 못해도 접근할 수 있도록 보장하는 성질은?\n\n① 위치 투명성\n② 복제 투명성\n③ 분할 투명성\n④ 장애 투명성', 'MCQ', 1, '정답: 1. 위치 투명성은 데이터가 어디에 저장되어 있는지 사용자가 몰라도 접근할 수 있게 해 주는 성질이다.\n\n**오답 풀이**\n- 1번: 위치 투명성은 물리적 위치 은닉과 관련된다.\n- 2번: 복제 투명성은 데이터 복제 여부를 사용자에게 숨긴다.\n- 3번: 분할 투명성은 데이터 분할 여부를 사용자에게 숨긴다.\n- 4번: 장애 투명성은 장애가 발생해도 서비스가 지속되도록 보장한다.\n\n**보충 개념**\n분산 데이터베이스는 위치, 중복, 분할, 장애 투명성 등을 제공한다.',
   '분산 데이터베이스', 1, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '속성 A의 각 값마다 속성 B의 값이 오직 하나만 결정될 때, ‘B는 A에 ( )이다’라고 한다.\n\n① 완전 종속\n② 함수적 종속\n③ 다중치 종속\n④ 결합 종속', 'MCQ', 2, '정답: 2. A 값이 정해지면 B 값이 하나로 결정되는 관계를 B가 A에 함수적으로 종속된다고 한다.\n\n**오답 풀이**\n- 1번: 완전 종속은 복합키 전체에 종속되는 경우를 의미한다.\n- 2번: 함수적 종속은 결정자와 종속자의 관계를 가리킨다.\n- 3번: 다중치 종속은 한 속성값에 여러 독립적인 값 집합이 대응되는 경우이다.\n- 4번: 결합 종속은 릴레이션 분해와 조인 복원과 관련된다.\n\n**보충 개념**\n함수 종속은 정규화에서 중복과 이상 현상을 분석하는 핵심 개념이다.',
   '함수 종속', 2, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '데이터 모델링 단계 중 DBMS 선정과 관련이 깊고 저장 구조를 설계하는 단계는?\n\n① 요구사항 분석\n② 개념적 설계\n③ 논리적 설계\n④ 물리적 설계', 'MCQ', 4, '정답: 4. 물리적 설계는 특정 DBMS와 저장 구조, 인덱스, 접근 경로 등을 결정하는 단계이다.\n\n**오답 풀이**\n- 1번: 요구사항 분석은 사용자 요구를 파악하는 단계이다.\n- 2번: 개념적 설계는 개체와 관계를 추상화하는 단계이다.\n- 3번: 논리적 설계는 논리 스키마를 설계하는 단계이다.\n- 4번: 물리적 설계는 저장 구조와 접근 방법을 설계한다.\n\n**보충 개념**\n데이터베이스 설계는 요구사항 분석, 개념적 설계, 논리적 설계, 물리적 설계, 구현 순으로 진행된다.',
   '물리적 설계', 2, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'SQL 집계 함수 중 그룹별 데이터의 개수를 구하는 함수는?\n\n① SUM()\n② AVG()\n③ COUNT()\n④ MAX()', 'MCQ', 3, '정답: 3. COUNT()는 행 또는 값의 개수를 구하는 집계 함수이다.\n\n**오답 풀이**\n- 1번: SUM()은 합계를 구한다.\n- 2번: AVG()는 평균을 구한다.\n- 3번: COUNT()는 개수를 구한다.\n- 4번: MAX()는 최댓값을 구한다.\n\n**보충 개념**\n집계 함수는 GROUP BY와 함께 사용해 그룹별 통계를 산출할 수 있다.',
   '집계 함수', 1, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '데이터베이스 설계 순서로 알맞은 것은?\n\n① 요구분석 → 논리 → 개념 → 물리 → 구현\n② 요구분석 → 개념 → 논리 → 물리 → 구현\n③ 개념 → 요구분석 → 논리 → 구현 → 물리\n④ 논리 → 개념 → 물리 → 요구분석 → 구현', 'MCQ', 2, '정답: 2. 데이터베이스 설계는 요구사항 분석, 개념적 설계, 논리적 설계, 물리적 설계, 구현 순으로 진행된다.\n\n**오답 풀이**\n- 1번: 개념 설계와 논리 설계의 순서가 뒤바뀌어 있다.\n- 2번: 올바른 설계 순서이다.\n- 3번: 요구분석이 개념 설계보다 먼저 수행되어야 한다.\n- 4번: 전체 단계 순서가 부적절하다.\n\n**보충 개념**\n개념 설계는 ERD, 논리 설계는 릴레이션 스키마, 물리 설계는 저장 구조와 인덱스 설계와 관련된다.',
   '데이터베이스 설계', 1, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '파이썬 리스트 `a = [10, 20, 30, 40, 50, 60, 70]`일 때 `print(a[1:6:2])`의 실행 결과는?\n\n① [10, 30, 50]\n② [20, 40, 60]\n③ [20, 30, 40]\n④ [10, 20, 30]', 'MCQ', 2, '정답: 2. 슬라이싱 `a[1:6:2]`는 인덱스 1부터 5까지 2칸씩 선택하므로 20, 40, 60이 추출된다.\n\n**오답 풀이**\n- 1번: 시작 인덱스를 0으로 잘못 본 결과이다.\n- 2번: 인덱스 1, 3, 5의 값이므로 정확하다.\n- 3번: step 2가 반영되지 않은 결과이다.\n- 4번: 시작 인덱스와 범위가 맞지 않는다.\n\n**보충 개념**\n파이썬 슬라이싱은 `[start:end:step]` 형식이며 end 인덱스는 포함되지 않는다.',
   'Python 슬라이싱', 2, @mock_exam_id, 61, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 파이썬(Python) 코드 중 1부터 매개변수로 전달받은 n까지 자연수의 합을 구해 반환하는 함수로 가장 알맞은 것은?\n\n① def sum_func(n):\n    return sum(range(1, n + 1))\n② def sum_func(n):\n    result = 0\n    for i in range(n):\n        result += i\n    return result\n③ def sum_func(n):\n    return sum(n)\n④ def sum_func(n):\n    return sum(range(1, n))', 'MCQ', 1, '정답: 1. `range(1, n + 1)`은 1부터 n까지의 정수를 생성하므로 자연수의 합을 정확히 구할 수 있다.\n\n**오답 풀이**\n- 1번: 1부터 n까지의 합을 정확히 구한다.\n- 2번: `range(n)`은 0부터 n-1까지이므로 n이 포함되지 않는다.\n- 3번: 정수 n은 반복 가능한 객체가 아니므로 오류가 발생한다.\n- 4번: `range(1, n)`은 n을 포함하지 않는다.\n\n**보충 개념**\n파이썬 `range(a, b)`는 a 이상 b 미만의 정수를 생성한다.',
   'Python 함수', 2, @mock_exam_id, 62, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C언어 연산자 중 우선순위가 가장 높은 것은?\n\n① +\n② &&\n③ ==\n④ %', 'MCQ', 4, '정답: 4. 나머지 연산자 `%`는 산술 연산자에 속하며 비교, 동등, 논리 연산자보다 우선순위가 높다.\n\n**오답 풀이**\n- 1번: `+`도 산술 연산자이지만, 보기 가운데 `%`가 더 구체적인 곱셈 계열의 산술 연산자이다.\n- 2번: `&&`는 논리 AND로 우선순위가 낮은 편이다.\n- 3번: `==`는 동등 비교 연산자로 산술 연산자보다 낮다.\n- 4번: `%`는 우선순위가 높은 산술 연산자이다.\n\n**보충 개념**\nC언어에서는 산술 연산자가 관계, 동등, 논리 연산자보다 먼저 계산된다.',
   'C 연산자', 2, @mock_exam_id, 63, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C언어 프로그램의 실행 결과로 알맞은 것은?\n\n```c\n#include <stdio.h>\n#include <string.h>\nint main() {\n    char s1[10] = "ABC";\n    char s2[10] = "DEF";\n    char *p1 = s1, *p2 = s2;\n    char temp = *(p1 + 1);\n    *(p1 + 1) = *(p2 + 1);\n    *(p2 + 1) = temp;\n    strcat(s1, s2);\n    printf("%s", s1);\n    return 0;\n}\n```\n\n① DBFAEC\n② ABCDEF\n③ AECDBF\n④ ADCFFB', 'MCQ', 3, '정답: 3. s1의 두 번째 문자 B와 s2의 두 번째 문자 E를 교환하면 s1은 AEC, s2는 DBF가 되며, strcat으로 이어 붙이면 AECDBF가 된다.\n\n**오답 풀이**\n- 1번: 문자열 결합 전후의 순서를 잘못 추적한 결과이다.\n- 2번: 문자 교환이 반영되지 않은 결과이다.\n- 3번: 교환 후 s1과 s2를 이어 붙인 결과와 일치한다.\n- 4번: s2의 문자 상태를 잘못 계산한 결과이다.\n\n**보충 개념**\n문자 배열과 포인터 문제는 각 문자의 위치 변화를 단계별로 추적하는 것이 좋다.',
   'C 문자열', 4, @mock_exam_id, 64, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'HRN 스케줄링에서 대기 시간이 20, 서비스 시간이 10일 때 우선순위 값은?\n\n① 1\n② 2\n③ 3\n④ 4', 'MCQ', 3, '정답: 3. HRN의 우선순위 = (대기시간 + 서비스시간) / 서비스시간 이므로 (20+10)/10 = 3이다.\n\n**오답 풀이**\n- 1번: 대기시간을 고려하지 않은 값이다.\n- 2번: 대기시간/서비스시간만 계산한 값이다.\n- 3번: HRN 공식으로 계산한 값이다.\n- 4번: 계산 결과보다 큰 값이다.\n\n**보충 개념**\nHRN은 긴 작업이 기아 상태에 빠지는 현상을 줄이기 위해 대기시간을 우선순위에 반영한다.',
   'HRN', 2, @mock_exam_id, 65, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '교착상태(Deadlock) 발생의 4가지 필요조건으로 보기 어려운 것은?\n\n① 상호 배제(Mutual Exclusion)\n② 점유 및 대기(Hold and Wait)\n③ 선점(Preemption)\n④ 환상 대기(Circular Wait)', 'MCQ', 3, '정답: 3. 교착상태의 필요조건은 상호 배제, 점유 및 대기, 비선점, 환상 대기이며, 선점은 발생 조건이 아니다.\n\n**오답 풀이**\n- 1번: 상호 배제는 교착상태의 필요조건이다.\n- 2번: 점유 및 대기는 교착상태의 필요조건이다.\n- 3번: 선점이 아니라 비선점이 필요조건이다.\n- 4번: 환상 대기는 교착상태의 필요조건이다.\n\n**보충 개념**\n교착상태는 네 가지 조건이 동시에 성립할 때 발생할 수 있다.',
   '교착상태', 2, @mock_exam_id, 66, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '기억장치 배치 전략 중 들어갈 수 있는 빈 공간 가운데 가장 큰 곳에 배치하는 전략은?\n\n① First Fit\n② Best Fit\n③ Worst Fit\n④ Next Fit', 'MCQ', 3, '정답: 3. Worst Fit은 사용 가능한 빈 공간 중 가장 큰 공간에 프로세스를 배치하는 전략이다.\n\n**오답 풀이**\n- 1번: First Fit은 처음 발견한 충분한 공간에 배치한다.\n- 2번: Best Fit은 가장 작은 충분한 공간에 배치한다.\n- 3번: Worst Fit은 가장 큰 공간에 배치한다.\n- 4번: Next Fit은 이전 검색 위치 다음부터 탐색한다.\n\n**보충 개념**\n연속 메모리 할당 전략에는 First Fit, Best Fit, Worst Fit, Next Fit 등이 있다.',
   '메모리 배치', 1, @mock_exam_id, 67, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 Java 코드에 `method(5, 5)`를 호출했을 때의 출력 결과로 알맞은 것은?\n\n```java\nvoid method(int a, int b) {\n    try {\n        int[] arr = new int[a];\n        System.out.print("A");\n        arr[b] = 10;\n        System.out.print("B");\n    } catch (Exception e) {\n        System.out.print("C");\n    } finally {\n        System.out.print("D");\n    }\n}\n```\n\n① AC\n② ACD\n③ ABD\n④ ABCD', 'MCQ', 2, '정답: 2. 배열 크기가 5이면 유효 인덱스는 0~4인데 arr[5] 접근에서 예외가 발생한다. 따라서 A 출력 후 catch에서 C, finally에서 D가 이어서 출력된다.\n\n**오답 풀이**\n- 1번: finally 블록의 D 출력이 빠져 있다.\n- 2번: A 출력 후 예외 발생, C와 D가 이어져 정확하다.\n- 3번: arr[5]에서 예외가 발생하므로 B는 출력되지 않는다.\n- 4번: B는 출력되지 않는다.\n\n**보충 개념**\nJava 배열은 인덱스 범위를 벗어나면 ArrayIndexOutOfBoundsException을 발생시킨다.',
   'Java 예외 처리', 3, @mock_exam_id, 68, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '파이썬 자료형 중 순서가 있고 한 번 생성된 후 값을 변경할 수 없는 자료형은?\n\n① List\n② Tuple\n③ Dictionary\n④ Set', 'MCQ', 2, '정답: 2. Tuple은 순서가 있으면서 한 번 생성된 뒤 원소를 변경할 수 없는 자료형이다.\n\n**오답 풀이**\n- 1번: List는 순서가 있지만 변경할 수 있다.\n- 2번: Tuple은 순서가 있고 변경 불가능하다.\n- 3번: Dictionary는 키-값 자료구조이며 변경할 수 있다.\n- 4번: Set은 순서가 없고 변경할 수 있다.\n\n**보충 개념**\n파이썬의 대표 불변 자료형에는 tuple, str, int 등이 있다.',
   'Python 자료형', 1, @mock_exam_id, 69, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C언어에서 2차원 배열 `int a[2][2];`가 선언되었을 때, 첫 번째 요소인 `a[0][0]`의 주소값을 가리키는 표현으로 옳지 않은 것은?\n\n① a\n② &a[0][0]\n③ *a\n④ &a[0]', 'MCQ', 4, '정답: 4. `&a[0]`은 첫 번째 행 전체를 가리키는 포인터로, `a[0][0]`의 주소와는 타입이 다르다.\n\n**오답 풀이**\n- 1번: `a`는 배열 문맥에서 첫 번째 행을 가리키며 주소값 자체는 배열의 시작 주소와 같다.\n- 2번: `&a[0][0]`은 첫 번째 요소의 주소이다.\n- 3번: `*a`는 첫 번째 행의 첫 원소 주소로 변환될 수 있다.\n- 4번: `&a[0]`은 첫 번째 행 전체를 가리키므로 타입이 달라 가장 부적절하다.\n\n**보충 개념**\n2차원 배열에서는 주소값이 같아 보여도 포인터 타입과 증가 단위가 달라질 수 있다.',
   'C 배열 포인터', 4, @mock_exam_id, 70, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'Java 접근 제어자 중 같은 패키지 내부와 자식 클래스에서만 접근이 가능한 것은?\n\n① public\n② private\n③ protected\n④ default', 'MCQ', 3, '정답: 3. protected는 같은 패키지에 속하거나 다른 패키지의 자식 클래스에서 접근할 수 있다.\n\n**오답 풀이**\n- 1번: public은 어디서나 접근 가능하다.\n- 2번: private은 같은 클래스 내부에서만 접근 가능하다.\n- 3번: protected는 같은 패키지와 자식 클래스에서 접근을 허용한다.\n- 4번: default는 같은 패키지에서만 접근 가능하다.\n\n**보충 개념**\nJava 접근 제어자는 public, protected, default, private 순으로 접근 범위가 좁아진다.',
   'Java 접근 제어자', 1, @mock_exam_id, 71, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C언어 코드의 출력 결과는?\n\n```c\nint a = 5, b = 3;\nprintf("%d", a & b);\n```\n\n① 1\n② 3\n③ 5\n④ 8', 'MCQ', 1, '정답: 1. 5는 이진수 0101, 3은 0011이며 비트 AND 연산 결과는 0001, 즉 1이다.\n\n**오답 풀이**\n- 1번: 5 & 3의 결과로 정확한 값이다.\n- 2번: 변수 b의 원래 값이다.\n- 3번: 변수 a의 원래 값이다.\n- 4번: 덧셈에 가까운 값이다.\n\n**보충 개념**\n비트 AND 연산은 두 비트가 모두 1일 때만 1을 결과로 만든다.',
   'C 비트 연산', 2, @mock_exam_id, 72, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '프로세스 상태 전이 중 실행 중이던 프로세스가 할당된 시간을 모두 사용하여 준비 상태로 변하는 전이는?\n\n① Dispatch\n② Block\n③ Timeout\n④ Wake up', 'MCQ', 3, '정답: 3. Timeout은 실행 중이던 프로세스가 시간 할당량을 모두 사용해 준비 상태로 돌아가는 전이이다.\n\n**오답 풀이**\n- 1번: Dispatch는 준비 상태에서 실행 상태로 가는 전이이다.\n- 2번: Block은 입출력 대기 등으로 대기 상태가 되는 전이이다.\n- 3번: Timeout은 실행 상태에서 준비 상태로 이동한다.\n- 4번: Wake up은 대기 상태에서 준비 상태로 이동한다.\n\n**보충 개념**\n시분할 시스템에서는 시간 할당량이 끝난 프로세스가 준비 큐로 돌아간다.',
   '프로세스 상태 전이', 1, @mock_exam_id, 73, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '가상 기억장치 관리 기법 중 프로그램을 동일한 크기의 단위로 나누어 관리하는 기법은?\n\n① Paging\n② Segmentation\n③ Compaction\n④ Fragmentation', 'MCQ', 1, '정답: 1. Paging은 프로그램과 메모리를 고정 크기의 페이지와 프레임 단위로 나누어 관리한다.\n\n**오답 풀이**\n- 1번: Paging은 동일한 크기 단위로 나눈다.\n- 2번: Segmentation은 논리적 의미를 가진 가변 크기 세그먼트로 나눈다.\n- 3번: Compaction은 단편화된 빈 공간을 모으는 작업이다.\n- 4번: Fragmentation은 단편화 자체를 의미한다.\n\n**보충 개념**\n페이징은 외부 단편화를 줄일 수 있지만 내부 단편화가 발생할 수 있다.',
   '페이징', 1, @mock_exam_id, 74, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 C언어 코드의 실행 결과는?\n\n```c\n#include <stdio.h>\nint main() {\n    int n = 10;\n    int *pt = &n;\n    printf("%d", &n + 1 - &n + *pt);\n    return 0;\n}\n```\n\n① 컴파일 에러\n② 10\n③ 11\n④ 21', 'MCQ', 3, '정답: 3. `&n + 1 - &n`의 포인터 차이는 1이고 `*pt`는 10이므로 결과는 1 + 10 = 11이다.\n\n**오답 풀이**\n- 1번: 시험 문맥에서는 같은 객체 기준 포인터 산술로 계산한다.\n- 2번: 포인터 차이 1이 누락된 결과이다.\n- 3번: 1 + 10 = 11이다.\n- 4번: 주소값 자체를 정수처럼 더한 값이 아니다.\n\n**보충 개념**\n포인터끼리의 뺄셈은 바이트 차이가 아니라 같은 타입 원소 개수의 차이로 계산된다.',
   'C 포인터', 4, @mock_exam_id, 75, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'Java에서 상위 클래스의 메소드를 하위 클래스에서 같은 시그니처로 재정의하는 것을 무엇이라 하는가?\n\n① Overloading\n② Overriding\n③ Encapsulation\n④ Inheritance', 'MCQ', 2, '정답: 2. Overriding은 상위 클래스의 메서드를 하위 클래스에서 같은 시그니처로 재정의하는 것이다.\n\n**오답 풀이**\n- 1번: Overloading은 같은 이름의 메서드를 매개변수 차이로 여러 개 정의하는 것이다.\n- 2번: Overriding은 상속받은 메서드를 재정의한다.\n- 3번: Encapsulation은 데이터와 메서드를 묶고 정보를 숨긴다.\n- 4번: Inheritance는 상속 자체를 의미한다.\n\n**보충 개념**\n오버라이딩은 다형성을 구현하는 핵심 메커니즘이다.',
   'Java 오버라이딩', 1, @mock_exam_id, 76, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '파이썬에서 `a = "Hello"`일 때 `a[:-1]`의 실행 결과는?\n\n① Hello\n② olleH\n③ Hell\n④ o', 'MCQ', 3, '정답: 3. `a[:-1]`은 처음부터 마지막 문자 직전까지 슬라이싱하므로 결과는 `Hell`이 된다.\n\n**오답 풀이**\n- 1번: 마지막 문자까지 포함한 전체 문자열이다.\n- 2번: 역순 문자열이다.\n- 3번: 마지막 문자 o를 제외한 결과이다.\n- 4번: 마지막 문자만 선택한 결과에 가깝다.\n\n**보충 개념**\n파이썬 슬라이싱에서 음수 인덱스 -1은 마지막 문자를 가리킨다.',
   'Python 슬라이싱', 1, @mock_exam_id, 77, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C언어에서 포인터 변수 p가 주소 100을 가리키고 int가 4바이트일 때, `p + 2`의 실제 주소값은?\n\n① 102\n② 104\n③ 108\n④ 112', 'MCQ', 3, '정답: 3. int 포인터에서 p+2는 int 두 칸만큼 이동하므로 100 + 2×4 = 108이 된다.\n\n**오답 풀이**\n- 1번: 바이트 단위로 2만 더한 값이다.\n- 2번: int 한 칸만 이동한 값이다.\n- 3번: int 두 칸 이동한 값이다.\n- 4번: int 세 칸 이동한 값이다.\n\n**보충 개념**\n포인터 연산은 가리키는 자료형의 크기 단위로 이동한다.',
   'C 포인터', 2, @mock_exam_id, 78, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '페이지 참조 순서가 `1, 2, 3, 4, 1, 2, 5, 3`인 8개의 페이지가 있고, 비어 있는 3개의 페이지 프레임이 있다. FIFO(First-In-First-Out) 알고리즘을 적용했을 때, 마지막 페이지 `3`까지 참조를 마친 뒤 프레임에 남아 있는 페이지 번호는? (순서는 무관)\n\n① 4, 1, 2\n② 3, 4, 5\n③ 2, 5, 3\n④ 1, 2, 5', 'MCQ', 3, '정답: 3. FIFO 방식으로 페이지를 적재하면 마지막 참조 3 처리 후 프레임에는 5, 3, 2가 남으므로 순서와 관계없이 2, 5, 3이 된다.\n\n**오답 풀이**\n- 1번: 4와 1은 이후 단계에서 교체된다.\n- 2번: 4는 마지막 상태에 남아 있지 않는다.\n- 3번: 최종 프레임 구성과 일치한다.\n- 4번: 1은 이후 단계에서 교체된다.\n\n**보충 개념**\nFIFO는 가장 먼저 들어온 페이지를 가장 먼저 교체하는 페이지 교체 알고리즘이다.',
   'FIFO 페이지 교체', 3, @mock_exam_id, 79, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '운영체제의 목적과 가장 거리가 먼 것은?\n\n① 처리 능력 향상\n② 반환 시간 단축\n③ 신뢰도 향상\n④ 사용자 편의성 배제', 'MCQ', 4, '정답: 4. 운영체제는 사용자 편의성을 높이는 것을 지향하므로, 사용자 편의성을 배제하는 것은 운영체제의 목적과 어긋난다.\n\n**오답 풀이**\n- 1번: 처리 능력 향상은 운영체제의 목적이다.\n- 2번: 반환 시간 단축은 운영체제의 목적이다.\n- 3번: 신뢰도 향상은 운영체제의 목적이다.\n- 4번: 사용자 편의성 배제는 운영체제의 목적과 반대된다.\n\n**보충 개념**\n운영체제의 대표 목적에는 처리 능력 향상, 반환 시간 단축, 사용 가능도 향상, 신뢰도 향상 등이 있다.',
   '운영체제 목적', 1, @mock_exam_id, 80, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '정보 보안의 3대 요소 중 인가된 사용자만이 정보에 접근할 수 있도록 보장하는 것은?\n\n① 기밀성(Confidentiality)\n② 무결성(Integrity)\n③ 가용성(Availability)\n④ 부인 방지(Non-repudiation)', 'MCQ', 1, '정답: 1. 기밀성은 인가된 사용자만이 정보에 접근할 수 있도록 보장하는 보안 요소이다.\n\n**오답 풀이**\n- 1번: 기밀성은 비인가 접근을 막는다.\n- 2번: 무결성은 정보가 변조되지 않도록 보장한다.\n- 3번: 가용성은 필요한 시점에 정보와 서비스 이용이 가능하도록 보장한다.\n- 4번: 부인 방지는 어떤 행위에 대해 사실을 부인하지 못하도록 하는 보안 속성이다.\n\n**보충 개념**\n정보보안 3요소는 기밀성, 무결성, 가용성이다.',
   '정보보안 3요소', 1, @mock_exam_id, 81, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '사용자 인증 요소 중 지식(Something you know)에 해당하는 것은?\n\n① 지문\n② 스마트카드\n③ 패스워드\n④ 홍채', 'MCQ', 3, '정답: 3. 패스워드는 사용자가 알고 있는 정보를 활용하는 지식 기반 인증 요소이다.\n\n**오답 풀이**\n- 1번: 지문은 생체 기반 인증 요소이다.\n- 2번: 스마트카드는 소유 기반 인증 요소이다.\n- 3번: 패스워드는 지식 기반 인증 요소이다.\n- 4번: 홍채는 생체 기반 인증 요소이다.\n\n**보충 개념**\n인증 요소는 지식, 소유, 생체 기반 요소로 구분할 수 있다.',
   '인증 요소', 1, @mock_exam_id, 82, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'OSI 7계층 중 물리적 매체를 통해 비트(Bit) 흐름을 전송하는 계층은?\n\n① 물리 계층\n② 데이터 링크 계층\n③ 네트워크 계층\n④ 전송 계층', 'MCQ', 1, '정답: 1. 물리 계층은 전기적·기계적 신호를 통해 비트 흐름을 전송하는 계층이다.\n\n**오답 풀이**\n- 1번: 물리 계층은 비트를 전송한다.\n- 2번: 데이터 링크 계층은 프레임 단위로 전송한다.\n- 3번: 네트워크 계층은 패킷 전달과 라우팅을 담당한다.\n- 4번: 전송 계층은 세그먼트 단위 전송과 신뢰성을 담당한다.\n\n**보충 개념**\nOSI 7계층의 하위 계층은 물리적 전송과 데이터 전달을 책임진다.',
   'OSI 7계층', 1, @mock_exam_id, 83, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'TCP/IP 프로토콜 중 네트워크 계층에 속하지 않는 프로토콜은?\n\n① IP\n② RARP\n③ ICMP\n④ UDP', 'MCQ', 4, '정답: 4. UDP는 전송 계층 프로토콜이며 네트워크 계층에 속하지 않는다.\n\n**오답 풀이**\n- 1번: IP는 네트워크 계층 프로토콜이다.\n- 2번: RARP는 주소 변환과 관련해 네트워크 계층 프로토콜로 분류된다.\n- 3번: ICMP는 네트워크 계층의 제어 메시지 프로토콜이다.\n- 4번: UDP는 전송 계층 프로토콜이다.\n\n**보충 개념**\nTCP와 UDP는 전송 계층에서 종단 간 데이터 전달을 담당한다.',
   'TCP/IP 계층', 1, @mock_exam_id, 84, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IP 주소를 그에 대응하는 물리적 하드웨어 주소(MAC)로 변환해 주는 프로토콜은?\n\n① RARP\n② ARP\n③ DHCP\n④ DNS', 'MCQ', 2, '정답: 2. ARP는 IP 주소를 MAC 주소로 변환해 주는 프로토콜이다.\n\n**오답 풀이**\n- 1번: RARP는 MAC 주소를 IP 주소로 변환한다.\n- 2번: ARP는 IP 주소를 MAC 주소로 변환한다.\n- 3번: DHCP는 IP 주소를 자동으로 할당한다.\n- 4번: DNS는 도메인 이름을 IP 주소로 변환한다.\n\n**보충 개념**\nARP 요청은 같은 네트워크 내에서 브로드캐스트로 전달된다.',
   'ARP', 1, @mock_exam_id, 85, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IPv6에 대한 설명으로 옳지 않은 것은?\n\n① 128비트 주소 체계를 사용한다.\n② 헤더의 크기가 40바이트로 고정되어 있다.\n③ IPv4와 호환성이 전혀 없다.\n④ 유니캐스트, 멀티캐스트, 애니캐스트 주소 방식을 사용한다.', 'MCQ', 3, '정답: 3. IPv6는 IPv4와의 전환을 위해 듀얼 스택, 터널링, 주소 변환 같은 전환 기술을 제공하므로, 호환성이 전혀 없다는 설명은 옳지 않다.\n\n**오답 풀이**\n- 1번: IPv6는 128비트 주소 체계를 사용한다.\n- 2번: IPv6의 기본 헤더는 40바이트이다.\n- 3번: IPv4와의 전환 기술이 존재한다.\n- 4번: IPv6는 유니캐스트, 멀티캐스트, 애니캐스트를 지원한다.\n\n**보충 개념**\nIPv6는 브로드캐스트를 사용하지 않는다.',
   'IPv6', 2, @mock_exam_id, 86, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '시스템에 과도한 데이터를 보내 자원을 고갈시켜 서비스를 중단시키는 공격 방식은?\n\n① DoS\n② Sniffing\n③ Spoofing\n④ Phishing', 'MCQ', 1, '정답: 1. DoS는 과도한 요청이나 데이터를 발생시켜 시스템 자원을 고갈시키고 서비스를 방해하는 공격이다.\n\n**오답 풀이**\n- 1번: DoS는 서비스 거부 공격이다.\n- 2번: Sniffing은 네트워크 트래픽을 도청하는 공격이다.\n- 3번: Spoofing은 신분이나 주소를 위조하는 공격이다.\n- 4번: Phishing은 사용자를 속여 정보를 빼내는 공격이다.\n\n**보충 개념**\nDoS 공격은 가용성을 침해하는 대표적 공격이다.',
   'DoS', 1, @mock_exam_id, 87, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '대칭키 암호화 알고리즘에 해당하는 것은?\n\n① RSA\n② AES\n③ ECC\n④ ElGamal', 'MCQ', 2, '정답: 2. AES는 대표적인 대칭키 블록 암호 알고리즘이다.\n\n**오답 풀이**\n- 1번: RSA는 공개키 암호 알고리즘이다.\n- 2번: AES는 대칭키 암호 알고리즘이다.\n- 3번: ECC는 공개키 기반의 암호 기술이다.\n- 4번: ElGamal은 공개키 암호 알고리즘이다.\n\n**보충 개념**\n대칭키 암호는 암호화와 복호화에 동일한 키를 사용한다.',
   '대칭키 암호', 1, @mock_exam_id, 88, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '네트워크 장비 중 서로 다른 프로토콜을 사용하는 네트워크를 연결하면서 경로를 선택해 주는 장비는?\n\n① 리피터\n② 허브\n③ 브리지\n④ 라우터', 'MCQ', 4, '정답: 4. 라우터는 네트워크 계층에서 경로를 선택하고 서로 다른 네트워크 사이의 패킷 전달을 담당한다.\n\n**오답 풀이**\n- 1번: 리피터는 물리 계층에서 신호를 재생한다.\n- 2번: 허브는 물리 계층 장비이다.\n- 3번: 브리지는 데이터 링크 계층에서 LAN 세그먼트를 연결한다.\n- 4번: 라우터는 경로 선택 기능을 수행한다.\n\n**보충 개념**\n라우터는 IP 주소를 토대로 패킷의 전달 경로를 결정한다.',
   '라우터', 1, @mock_exam_id, 89, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '클라우드 서비스 유형 중 인프라(서버, 스토리지 등)를 서비스 형태로 제공하는 방식은?\n\n① SaaS\n② PaaS\n③ IaaS\n④ BaaS', 'MCQ', 3, '정답: 3. IaaS는 서버, 스토리지, 네트워크 같은 인프라 자원을 서비스 형태로 제공한다.\n\n**오답 풀이**\n- 1번: SaaS는 소프트웨어를 서비스로 제공한다.\n- 2번: PaaS는 개발 플랫폼을 서비스로 제공한다.\n- 3번: IaaS는 인프라 자원을 제공한다.\n- 4번: BaaS는 블록체인이나 백엔드 기능을 서비스로 제공하는 의미로 사용된다.\n\n**보충 개념**\n클라우드 서비스 모델에는 IaaS, PaaS, SaaS 등이 있다.',
   'IaaS', 1, @mock_exam_id, 90, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '네트워크 토폴로지 중 중앙의 컴퓨터를 중심으로 모든 단말기가 연결된 형태는?\n\n① 성형(Star)\n② 링형(Ring)\n③ 버스형(Bus)\n④ 망형(Mesh)', 'MCQ', 1, '정답: 1. 성형 토폴로지는 중앙 장치에 모든 노드가 개별적으로 연결되는 구조이다.\n\n**오답 풀이**\n- 1번: 성형은 중앙 장치를 중심으로 연결된다.\n- 2번: 링형은 노드들이 고리 형태로 연결된다.\n- 3번: 버스형은 하나의 공통 회선을 함께 사용한다.\n- 4번: 망형은 여러 노드가 그물망처럼 연결된다.\n\n**보충 개념**\n성형 구조는 중앙 장치에 장애가 발생할 경우 전체 네트워크가 영향을 크게 받는다.',
   '네트워크 토폴로지', 1, @mock_exam_id, 91, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '거리 벡터 라우팅 프로토콜로, 최대 홉(Hop) 수를 15로 제한하는 것은?\n\n① OSPF\n② RIP\n③ BGP\n④ IGRP', 'MCQ', 2, '정답: 2. RIP는 거리 벡터 라우팅 프로토콜이며 최대 홉 수가 15로 제한된다.\n\n**오답 풀이**\n- 1번: OSPF는 링크 상태 라우팅 프로토콜이다.\n- 2번: RIP는 거리 벡터 방식이며 최대 홉 수가 15이다.\n- 3번: BGP는 경로 벡터 방식의 외부 게이트웨이 프로토콜이다.\n- 4번: IGRP는 Cisco의 거리 벡터 프로토콜이지만, 최대 홉 수 15 제한의 대표 답은 RIP이다.\n\n**보충 개념**\nRIP는 단순하다는 장점이 있지만 대규모 네트워크에는 적합하지 않다.',
   'RIP', 2, @mock_exam_id, 92, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '비대칭키(공개키) 암호화 방식에 대한 설명으로 알맞은 것은?\n\n① 암호화 키와 복호화 키가 동일하다.\n② 키 분배 및 관리가 어렵다.\n③ 대칭키 방식보다 속도가 느리다.\n④ DES가 대표적인 알고리즘이다.', 'MCQ', 3, '정답: 3. 공개키 암호는 수학적으로 복잡한 연산을 사용하기 때문에 일반적으로 대칭키 암호보다 속도가 느리다.\n\n**오답 풀이**\n- 1번: 비대칭키 암호는 공개키와 개인키 두 종류를 사용한다.\n- 2번: 공개키 암호는 대칭키보다 키 분배가 상대적으로 수월하다.\n- 3번: 비대칭키 방식은 일반적으로 속도가 느리다.\n- 4번: DES는 대칭키 암호 알고리즘이다.\n\n**보충 개념**\n공개키 암호의 대표 알고리즘으로는 RSA, ECC, ElGamal이 있다.',
   '비대칭키 암호', 2, @mock_exam_id, 93, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '침입 탐지 시스템(IDS)의 기능으로 보기 어려운 것은?\n\n① 네트워크 트래픽 분석\n② 비정상적인 침입 징후 탐지\n③ 침입 발생 시 즉각적인 패킷 차단 및 수정\n④ 로그 기록 및 경고 발생', 'MCQ', 3, '정답: 3. IDS는 침입을 탐지하고 경고하는 시스템이며, 즉각적인 차단과 수정은 IPS의 영역에 가깝다.\n\n**오답 풀이**\n- 1번: IDS는 네트워크 트래픽을 분석할 수 있다.\n- 2번: IDS는 이상 징후나 공격 패턴을 탐지한다.\n- 3번: 패킷 차단과 수정은 IPS의 능동 대응에 해당한다.\n- 4번: IDS는 로그와 경고를 생성한다.\n\n**보충 개념**\nIDS는 탐지 중심, IPS는 탐지와 차단을 함께 수행하는 보안 시스템이다.',
   'IDS', 2, @mock_exam_id, 94, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '무선랜 보안 프로토콜 중 WEP의 취약점을 보완하기 위해 등장한 방식은?\n\n① WPA\n② HTTP\n③ FTP\n④ SMTP', 'MCQ', 1, '정답: 1. WPA는 WEP의 취약점을 보완하기 위해 만들어진 무선 네트워크 보안 규격이다.\n\n**오답 풀이**\n- 1번: WPA는 WEP보다 강화된 무선 보안 방식이다.\n- 2번: HTTP는 웹 통신 프로토콜이다.\n- 3번: FTP는 파일 전송 프로토콜이다.\n- 4번: SMTP는 이메일 전송 프로토콜이다.\n\n**보충 개념**\n무선 보안은 WEP, WPA, WPA2, WPA3 순으로 발전해 왔다.',
   '무선 보안', 1, @mock_exam_id, 95, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '대규모 데이터를 분산 처리하기 위한 자바 기반의 오픈 소스 프레임워크는?\n\n① Hadoop\n② MySQL\n③ Oracle\n④ Python', 'MCQ', 1, '정답: 1. Hadoop은 대규모 데이터를 분산 저장하고 처리하기 위해 개발된 자바 기반의 오픈소스 프레임워크이다.\n\n**오답 풀이**\n- 1번: Hadoop은 분산 처리 프레임워크이다.\n- 2번: MySQL은 관계형 DBMS이다.\n- 3번: Oracle은 상용 DBMS이다.\n- 4번: Python은 프로그래밍 언어이다.\n\n**보충 개념**\nHadoop은 HDFS와 MapReduce를 기반으로 대용량 데이터를 처리한다.',
   'Hadoop', 1, @mock_exam_id, 96, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '물리적으로 떨어져 있는 단말기들을 논리적으로 하나의 LAN처럼 구성하는 기술은?\n\n① VPN\n② VLAN\n③ WAN\n④ PAN', 'MCQ', 2, '정답: 2. VLAN은 물리적 위치와 무관하게 논리적으로 LAN을 분리하거나 구성할 수 있게 해 주는 기술이다.\n\n**오답 풀이**\n- 1번: VPN은 공중망을 통해 사설망처럼 안전하게 연결하는 기술이다.\n- 2번: VLAN은 논리적인 LAN 구성을 가능하게 한다.\n- 3번: WAN은 광역 네트워크이다.\n- 4번: PAN은 개인 영역 네트워크이다.\n\n**보충 개념**\nVLAN은 브로드캐스트 도메인을 분리하여 보안성과 관리 효율을 함께 높여 준다.',
   'VLAN', 1, @mock_exam_id, 97, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '시큐어 코딩(Secure Coding) 가이드의 분류 중 입력 데이터 검증 및 표현 영역에 해당하는 보안 약점은?\n\n① SQL 삽입(Injection)\n② 캡슐화 위반\n③ 스택 오버플로\n④ 시간 및 상태 오류', 'MCQ', 1, '정답: 1. SQL 삽입은 입력값 검증이 부족할 때 발생하는 대표적인 입력 데이터 검증 및 표현 관련 보안 약점이다.\n\n**오답 풀이**\n- 1번: SQL 삽입은 입력값 검증이 미흡할 때 발생한다.\n- 2번: 캡슐화 위반은 코드 품질이나 객체지향 설계와 관련된 약점이다.\n- 3번: 스택 오버플로는 메모리 처리상의 약점이다.\n- 4번: 시간 및 상태 오류는 동시성이나 상태 관리상의 약점이다.\n\n**보충 개념**\nSQL 삽입을 방지하기 위해 PreparedStatement, 입력값 검증, 특수문자 처리 등을 활용한다.',
   'SQL Injection', 1, @mock_exam_id, 98, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '디지털 저작권 관리(DRM) 구성 요소 중 콘텐츠를 암호화하여 배포 가능한 형태로 만들어 주는 것은?\n\n① DRM 컨트롤러\n② 클리어링 하우스\n③ 패키저(Packager)\n④ 보안 컨테이너', 'MCQ', 3, '정답: 3. 패키저는 콘텐츠를 암호화하여 배포 가능한 형태로 묶어 주는 DRM 구성 요소이다.\n\n**오답 풀이**\n- 1번: DRM 컨트롤러는 콘텐츠 이용 권한을 통제한다.\n- 2번: 클리어링 하우스는 라이선스와 결제 관리를 담당한다.\n- 3번: 패키저는 콘텐츠를 암호화해 배포 형태로 만든다.\n- 4번: 보안 컨테이너는 콘텐츠를 안전하게 유통하기 위한 전자적 보안 장치이다.\n\n**보충 개념**\nDRM은 콘텐츠 보호를 위해 암호화, 키 관리, 라이선스 관리, 정책 제어를 수행한다.',
   'DRM', 2, @mock_exam_id, 99, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '서버 장애 발생 시 백업 서버가 즉시 업무를 이어받아 수행하도록 하는 고가용성 솔루션은?\n\n① HACMP\n② RAID\n③ UPS\n④ NAS', 'MCQ', 1, '정답: 1. HACMP는 장애가 발생했을 때 대기 서버가 서비스를 인계받아 고가용성을 제공하는 클러스터링 솔루션이다.\n\n**오답 풀이**\n- 1번: HACMP는 고가용성 클러스터링 솔루션이다.\n- 2번: RAID는 디스크 중복 구성을 위한 기술이다.\n- 3번: UPS는 무정전 전원 공급 장치이다.\n- 4번: NAS는 네트워크 기반 파일 저장 장치이다.\n\n**보충 개념**\n고가용성 솔루션은 장애 발생 시 서비스 중단 시간을 최소화하는 것을 지향한다.',
   'HACMP', 1, @mock_exam_id, 100, 'NONE', NULL, NOW(6), NOW(6))
;